var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"젠장…!","JPN":"くそ……！","ENG":"Dammit...!","TWN":"該死……！"},"stage":{"bg":"SWORDGRAVE_STAR","bgm":"HOUSE_OF_THE_RISING_SUN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"여기까지 어떻게 왔는데…! 고작 몇 걸음 남았단 말이다!","JPN":"やっとここまで来れたのに……！　あと数歩のところだったのに！","ENG":"We were this close...! Just a couple more steps!","TWN":"好不容易才走到這裡……！就差幾步了！"},"stage":{"bg":"SWORDGRAVE_STAR","bgm":"HOUSE_OF_THE_RISING_SUN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"이것도 망할 운명이란 거냐? 탐미엘! 언제까지 이딴 희망고문만 할 셈이야!","JPN":"これも運命ってやつなの？　タミエル！　いつまでこんなことを続けるつもりなんだ！","ENG":"Are you saying this is fate too? Tammiel! How much longer are you going to give us false hope like this?!","TWN":"這也是該死的命運嗎？塔米爾！你打算一直這樣用希望來折磨我嗎！"},"stage":{"bg":"SWORDGRAVE_STAR","bgm":"HOUSE_OF_THE_RISING_SUN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"SWORDGRAVE_STAR","bgm":"HOUSE_OF_THE_RISING_SUN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"검이… 빛나고 있어?","JPN":"剣が……光ってる？","ENG":"The sword... it's glowing?","TWN":"斷劍……在發光？"},"stage":{"bg":"SWORDGRAVE_STAR","bgm":"HOUSE_OF_THE_RISING_SUN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"SYS_ARC_NULL_NULL","text":{"KOREA":"관리 권한자 접근을 확인했습니다.","JPN":"管理権限者の接近を確認しました。","ENG":"Supervisor confirmed.","TWN":"確認管理許可權者接入。"},"stage":{"bg":"MAINSTREAM_000002","bgm":"HOUSE_OF_THE_RISING_SUN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L14_1","type":"dialog","speaker":"SYS_ARC_NULL_NULL","text":{"KOREA":"임시 동결 해제. 시스템 온라인.","JPN":"臨時凍結を解除。システムオン。","ENG":"Temporary cryostasis, disabled. System online.","TWN":"臨時凍結解除。系統，上線。"},"stage":{"bg":"MAINSTREAM_000004","bgm":"HOUSE_OF_THE_RISING_SUN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L15_1","type":"dialog","speaker":"SYS_ARC_NULL_NULL","text":{"KOREA":"용무가 있으십니까?","JPN":"何のご用でしょうか？","ENG":"May I help you?","TWN":"需要什麼協助？"},"stage":{"bg":"MAINSTREAM_000004","bgm":"HOUSE_OF_THE_RISING_SUN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L17_1","type":"dialog","speaker":"MOM_NPC_BIRDCAGE_NULL","text":{"KOREA":"내가 여기서 지낸 뒤로… 시간이 얼마나 지났죠?","JPN":"私がここで過ごして……どれぐらい経ちましたか？","ENG":"How long has it been... since I've been here?","TWN":"我……在這裡待多久了？"},"stage":{"bg":"MAINSTREAM_000004","bgm":"HOUSE_OF_THE_RISING_SUN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L18_1","type":"dialog","speaker":"SYS_ARC_NULL_NULL","text":{"KOREA":"이 장소는 방주의 동결 프로세스에 의해 모든 것이 멈춰있습니다.","JPN":"この場所は箱舟の凍結プロセスによってすべてが停止しています。","ENG":"Everything here has been stopped by the Ark's cryostasis protocol.","TWN":"目前這個空間的一切因為方舟的凍結保存協議而停滯了。"},"stage":{"bg":"MAINSTREAM_000004","bgm":"HOUSE_OF_THE_RISING_SUN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L19_1","type":"dialog","speaker":"SYS_ARC_NULL_NULL","text":{"KOREA":"따라서 시간을 정의하는 것은 무의미합니다.","JPN":"よって、時間を定義することは無意味です。","ENG":"Thus, defining time here is meaningless.","TWN":"因此，在這裡定義時間是沒有意義的。"},"stage":{"bg":"MAINSTREAM_000004","bgm":"HOUSE_OF_THE_RISING_SUN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L20_1","type":"dialog","speaker":"SYS_ARC_NULL_NULL","text":{"KOREA":"권한자께서 사고하고 행동할 수 있는 이유는 이 세계를 정의하는 개념 그 자체이기 때문에 가능한 일입니다.","JPN":"権限者様が思考し、行動できるのは、この世界を定義する概念そのものだからです。","ENG":"The reason why you are still able to think and act is because you are the very concept that defines this world.","TWN":"許可權者之所以能夠思考和行動，是因為她本身就是定義這個世界的概念。"},"stage":{"bg":"MAINSTREAM_000004","bgm":"HOUSE_OF_THE_RISING_SUN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L22_1","type":"dialog","speaker":"MOM_NPC_BIRDCAGE_NULL","text":{"KOREA":"바깥에선… 얼마나 많은 시간이 흘렀나요?","JPN":"では外の世界では……どれぐらいの時間が経っていますか？","ENG":"How much time has passed... out there?","TWN":"外面……已經過了多久了？"},"stage":{"bg":"MAINSTREAM_000004","bgm":"HOUSE_OF_THE_RISING_SUN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L23_1","type":"dialog","speaker":"SYS_ARC_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"MAINSTREAM_000004","bgm":"HOUSE_OF_THE_RISING_SUN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L27_1","type":"dialog","speaker":"SYS_ARC_NULL_NULL","text":{"KOREA":"본함은 현재 공간 외부의 테라브레인과 동기화되어 있지 않아 그 질문에 정확한 답을 드리기 어렵습니다.","JPN":"本艦は現在、空間外部のテラブレインと同期していないため、その質問には答えられません。","ENG":"It is difficult to answer your question as this ship is currently not synced with Terrabrain outside of space.","TWN":"本艦目前未與空間外部的特拉大腦同步，因此很難準確回答你的問題。"},"stage":{"bg":"VOID","bgm":"HOUSE_OF_THE_RISING_SUN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L28_1","type":"dialog","speaker":"SYS_ARC_NULL_NULL","text":{"KOREA":"하지만, 동결 범위 바깥에 존재하는 천체의 변화를 동결 전후로 비교했을 때…","JPN":"しかし、凍結範囲外に存在する天体の変化を、凍結前と比較すると……","ENG":"However, by calculating the difference in the changes in celestial bodies outside the cryostasis range...","TWN":"但是，透過計算凍結範圍之外天體在凍結前後的變化……"},"stage":{"bg":"VOID","bgm":"HOUSE_OF_THE_RISING_SUN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L29_1","type":"dialog","speaker":"SYS_ARC_NULL_NULL","text":{"KOREA":"약 1억 6천 만 년 가량이 경과한 것으로 추정됩니다.","JPN":"およそ1億6千万年が経過していると推定されます。","ENG":"it is estimated that about 160 million years have passed.","TWN":"預估已經過了1億6千萬年。"},"stage":{"bg":"VOID","bgm":"HOUSE_OF_THE_RISING_SUN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L31_1","type":"dialog","speaker":"MOM_NPC_BIRDCAGE_NULL","text":{"KOREA":"스승님의 시간도… 그만큼 흘렀을까요?","JPN":"師匠の時間も……それぐらい経っているんでしょうか？","ENG":"Has that much time... also passed for Master?","TWN":"師父的時間……也流逝了這麼久嗎？"},"stage":{"bg":"VOID","bgm":"HOUSE_OF_THE_RISING_SUN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L32_1","type":"dialog","speaker":"SYS_ARC_NULL_NULL","text":{"KOREA":"시간은 상대적입니다. 차원 간 시차는 은하와 은하 사이의 간극보다 더 불규칙적이기 때문에 간단히 정의 내리기 어렵습니다.","JPN":"時間は相対的なものです。次元間の時差は、銀河と銀河の時差よりも不規則なものであるため、一言で定義することは難しいです。","ENG":"Time is relative. Interdimensional parallax is difficult to define as it is more irregular than the gap between galaxies.","TWN":"時間是相對的。次元間的時差比銀河與銀河之間的間隙更不規則，因此很難簡單定義。"},"stage":{"bg":"VOID","bgm":"HOUSE_OF_THE_RISING_SUN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L33_1","type":"dialog","speaker":"SYS_ARC_NULL_NULL","text":{"KOREA":"어쩌면 이곳보다 더 많은 시간이 흘렀을 수도 있고, 하루가 흘렀을 수도 있습니다.","JPN":"ここより長い時間が経っている可能性も、一日しか経っていない可能性もあります。","ENG":"More time could have passed than here, or perhaps only a day.","TWN":"也許那裡已經過了很長時間，也可能只過了一天。"},"stage":{"bg":"VOID","bgm":"HOUSE_OF_THE_RISING_SUN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L36_1","type":"dialog","speaker":"MOM_NPC_BIRDCAGE_NULL","text":{"KOREA":"…그러면 말이죠.","JPN":"じゃあ……","ENG":"...Then.","TWN":"……這麼說的話。"},"stage":{"bg":"MAINSTREAM_000004","bgm":"HOUSE_OF_THE_RISING_SUN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L37_1","type":"dialog","speaker":"MOM_NPC_BIRDCAGE_NULL","text":{"KOREA":"제가 스승님의 운명을 이용해 시간을 흐르게 해도… 이제 괜찮은 걸까요?","JPN":"もう……師匠の運命を使って、時間を動かしても……いいんでしょうか？","ENG":"Would it be okay... to use Master's fate to make time flow now?","TWN":"即使現在我用師父的命運讓時間流逝……也沒關係了嗎？"},"stage":{"bg":"MAINSTREAM_000004","bgm":"HOUSE_OF_THE_RISING_SUN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L38_1","type":"dialog","speaker":"SYS_ARC_NULL_NULL","text":{"KOREA":"모든 결정 권한은 권한자께 부여되어 있습니다.","JPN":"すべての決定への権限は、権限者様にあります。","ENG":"All authority has been granted to you.","TWN":"所有決策許可權均已授予許可權者。"},"stage":{"bg":"MAINSTREAM_000004","bgm":"HOUSE_OF_THE_RISING_SUN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L39_1","type":"dialog","speaker":"SYS_ARC_NULL_NULL","text":{"KOREA":"권한자께서 원하신다면 본함은 그 결정에 따라 격리를 해제할 뿐입니다.","JPN":"権限者様が望むのであれば、本艦はその決定に従い、隔離を解除します。","ENG":"If that is what you want, the ship will lift the isolation accordingly.","TWN":"如果許可權者希望，本艦將根據你的決定解除隔離。"},"stage":{"bg":"MAINSTREAM_000004","bgm":"HOUSE_OF_THE_RISING_SUN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L40_1","type":"dialog","speaker":"MOM_NPC_BIRDCAGE_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"MAINSTREAM_000004","bgm":"HOUSE_OF_THE_RISING_SUN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L42_1","type":"dialog","speaker":"HILDE_FENRIR_ADMIN_PAST","text":{"KOREA":"그땐 네가 가진 내 운명을 이용하면 돼.","JPN":"その時は、お前が持っている私の運命を利用すればいい。","ENG":"When it comes to that, use my fate.","TWN":"到那個時候，用我的命運就行了。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"HOUSE_OF_THE_RISING_SUN_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_ADMIN_PAST","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"HILDE_FENRIR_ADMIN_PAST","text":{"KOREA":"내 운명에 깃든 가능성이라면, 너희 두 사람 평생의 미래 정도는 보장할 수 있을 거다.","JPN":"私の運命に宿る可能性なら、お前たち2人の一生分の未来ぐらいは保証できるはずだ。","ENG":"With the possibilities within my fate, it'll be enough to guarantee the future of the two of you.","TWN":"如果是我命運中的可能性，足以保證你們兩個人一生的未來了。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"HOUSE_OF_THE_RISING_SUN_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_ADMIN_PAST","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"MOM_NPC_BIRDCAGE_NULL","text":{"KOREA":"운명에 깃든 가능성으로… 미래를 얻는다.","JPN":"運命に宿る可能性で……未来を手に入れる。","ENG":"With the possibilities inherent in fate... we obtain the future.","TWN":"由於命運中所賦予的可能性……我們獲得了未來。"},"stage":{"bg":"MAINSTREAM_000004","bgm":"HOUSE_OF_THE_RISING_SUN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L46_1","type":"dialog","speaker":"MOM_NPC_BIRDCAGE_NULL","text":{"KOREA":"어쩌면… 그게 스승님의 마지막 가르침일지도 모르겠네요.","JPN":"もしかしたら……それが師匠の最後の教えだったのかもしれませんね。","ENG":"Perhaps... that was Master's last lesson for me.","TWN":"或許……那就是師父最後的教誨吧。"},"stage":{"bg":"MAINSTREAM_000004","bgm":"HOUSE_OF_THE_RISING_SUN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L48_1","type":"dialog","speaker":"MOM_NPC_BIRDCAGE_NULL","text":{"KOREA":"돌아올 때까지 기다리기로 했는데… 죄송해요, 스승님.","JPN":"帰ってくるまで待つって約束したのに……ごめんなさい、師匠。","ENG":"I promised to wait until you returned... I'm sorry, Master.","TWN":"原本說好了等你回來的……對不起，師父。"},"stage":{"bg":"MAINSTREAM_000004","bgm":"HOUSE_OF_THE_RISING_SUN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L49_1","type":"dialog","speaker":"MOM_NPC_BIRDCAGE_NULL","text":{"KOREA":"못난 제자는… 약속을 지키지 못 할 것 같네요.","JPN":"出来損ないの弟子だから……その約束は、守れそうにありません。","ENG":"Your insubordinate apprentice... won't be able to keep her promise.","TWN":"愚鈍的徒弟……恐怕無法遵守約定了。"},"stage":{"bg":"MAINSTREAM_000004","bgm":"HOUSE_OF_THE_RISING_SUN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L1_1","type":"dialog","speaker":"MOM_NPC_BIRDCAGE_NULL","text":{"KOREA":"테라브레인.","JPN":"テラブレイン。","ENG":"Terrabrain.","TWN":"特拉大腦。"},"stage":{"bg":"MAINSTREAM_000004","bgm":"HOUSE_OF_THE_RISING_SUN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"말씀하십시오, 권한자.","JPN":"はい、権限者様。","ENG":"Yes, Supervisor?","TWN":"請說，管理許可權者。"},"stage":{"bg":"MAINSTREAM_000004","bgm":"HOUSE_OF_THE_RISING_SUN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"MOM_NPC_BIRDCAGE_NULL","text":{"KOREA":"계산해줘요.","JPN":"計算してください。","ENG":"Calculate.","TWN":"幫我算一下。"},"stage":{"bg":"MAINSTREAM_000004","bgm":"HOUSE_OF_THE_RISING_SUN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"MOM_NPC_BIRDCAGE_NULL","text":{"KOREA":"내 운명을 가능성으로 치환하면, 이 세계를 몇 년이나 지속할 수 있는지.","JPN":"私の運命を可能性に置換すれば、この世界をあと何年持続させられるのか。","ENG":"If I substitute my fate for possibilities, how many years would this world last?","TWN":"如果將我的命運轉化為可能性，這個世界還能持續幾年？"},"stage":{"bg":"BLACK","bgm":"HOUSE_OF_THE_RISING_SUN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"narration","speaker":null,"text":{"KOREA":"영원을 대가로 얻은… 십 수년이었다.","JPN":"永遠を対価に手に入れた……十数年だった。","ENG":"What I received in exchange for eternity was... ten and some years.","TWN":"以永恆為代價所交換得來的……僅僅是十幾年而已。"},"stage":{"bg":"COUNTERSIDE_GARDEN","bgm":"HOUSE_OF_THE_RISING_SUN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L13_1","type":"narration","speaker":null,"text":{"KOREA":"누군가의 이해를 바라지 않은 충동… 경솔한 판단… 한낱 이기심이었다.","JPN":"誰かの理解を求めない、衝動的で軽率な判断……あれは自己満足だった。","ENG":"It was an impulsive decision I didn't expect anyone to understand... A careless call... Selfishness.","TWN":"這只是個不求他人理解……輕率而衝動的判斷而已……是如此的自私。"},"stage":{"bg":"COUNTERSIDE_GARDEN","bgm":"HOUSE_OF_THE_RISING_SUN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_HEARTBEAT"},{"id":"L14_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"헉… 헉…","JPN":"はあ……はあ……","ENG":"*Huff* *Huff*","TWN":"呼……呼……"},"stage":{"bg":"COUNTERSIDE_GARDEN","bgm":"HOUSE_OF_THE_RISING_SUN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"…하아앗!!!","JPN":"……はああっ！！","ENG":"...Hraagh!!!","TWN":"……啊啊啊啊！！！"},"stage":{"bg":"COUNTERSIDE_GARDEN","bgm":"HOUSE_OF_THE_RISING_SUN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L17_1","type":"narration","speaker":null,"text":{"KOREA":"그럼에도 난… 그 선택을 한 순간도 후회한 적 없어.","JPN":"それでも私は……一瞬たりともその選択を後悔したことはない。","ENG":"Nevertheless... I have never regretted that decision.","TWN":"即便如此……我從未後悔過那個選擇。"},"stage":{"bg":"SKY_NIGHT","bgm":"HOUSE_OF_THE_RISING_SUN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_HEARTBEAT"},{"id":"L18_1","type":"narration","speaker":null,"text":{"KOREA":"비록 찰나처럼 짧은 시간이었지만… 영원함보다 소중한 널 얻었으니까.","JPN":"刹那のように短い時間だったけど……永遠よりも大切なあなたが生まれたから。","ENG":"Because, even if it was a fleeting moment... I got you. You're more precious than eternity.","TWN":"雖然只是短暫的片刻……但我得到了比永恆更珍貴的你。"},"stage":{"bg":"SKY_NIGHT","bgm":"HOUSE_OF_THE_RISING_SUN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_HEARTBEAT"},{"id":"L19_1","type":"narration","speaker":null,"text":{"KOREA":"결국 마지막이 이별로 끝날 줄 알면서도… 그 목소리, 그 온기, 그 미소가 보고 싶었으니까.","JPN":"お別れの結末しかないとわかっていても……その声が、その温もりが、その笑顔が欲しくて。","ENG":"Knowing that it would end in farewell... I wanted to hear your voice, feel your warmth, and see your smile.","TWN":"明知道最後會以離別告終……但還是想感受那個聲音……那個溫暖……那個微笑。"},"stage":{"bg":"SKY_NIGHT","bgm":"HOUSE_OF_THE_RISING_SUN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_HEARTBEAT"},{"id":"L21_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"윽…!","JPN":"うっ……！","ENG":"Ngh...!","TWN":"呃……！"},"stage":{"bg":"COUNTERSIDE_GARDEN","bgm":"HOUSE_OF_THE_RISING_SUN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L22_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"이 정도론…","JPN":"この程度じゃ……","ENG":"I'm not giving up...","TWN":"這點程度……"},"stage":{"bg":"COUNTERSIDE_GARDEN","bgm":"HOUSE_OF_THE_RISING_SUN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"…포기하지 않아!","JPN":"……諦めない！","ENG":"...that easily!","TWN":"……不會放棄的！"},"stage":{"bg":"COUNTERSIDE_GARDEN","bgm":"HOUSE_OF_THE_RISING_SUN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L25_1","type":"narration","speaker":null,"text":{"KOREA":"그러니까… 이런 이기적인 엄마를 미워하렴.","JPN":"だから……こんな勝手なお母さんを恨んでね。","ENG":"So... blame it all on your selfish mother.","TWN":"所以……恨這樣自私的媽媽吧。"},"stage":{"bg":"COUNTERSIDE_GARDEN","bgm":"HOUSE_OF_THE_RISING_SUN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_HEARTBEAT"},{"id":"L27_1","type":"narration","speaker":null,"text":{"KOREA":"널 비참하게 만들어서 미안해.","JPN":"あなたを悲しませてごめんなさい。","ENG":"I'm sorry for making you miserable.","TWN":"對不起，讓你變得如此悲慘。"},"stage":{"bg":"COUNTERSIDE_GARDEN","bgm":"HOUSE_OF_THE_RISING_SUN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_HEARTBEAT"},{"id":"L29_1","type":"narration","speaker":null,"text":{"KOREA":"영원보다 사랑하는… 나의 별님.","JPN":"永遠より大切な……私のお星さま。","ENG":"I love you more than eternity... my beloved star.","TWN":"我對你的愛超過永恆……我親愛的小星星。"},"stage":{"bg":"COUNTERSIDE_GARDEN","bgm":"HOUSE_OF_THE_RISING_SUN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_HEARTBEAT"},{"id":"L32_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"BLACK","bgm":"HOUSE_OF_THE_RISING_SUN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"미워할 리 없잖아요.","JPN":"恨むわけないでしょう。","ENG":"There's no way I would hate you.","TWN":"怎麼會討厭媽媽呢。"},"stage":{"bg":"BLACK","bgm":"HOUSE_OF_THE_RISING_SUN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"어떤 선택을 해도, 제가 가장 사랑하는 사람인 걸요.","JPN":"どんな選択をしても、私の一番大切な人ですもの。","ENG":"Because no matter what choice you made, you're still the person I love the most.","TWN":"無論做出什麼選擇，我都最愛你了。"},"stage":{"bg":"BLACK","bgm":"HOUSE_OF_THE_RISING_SUN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"그러니까…","JPN":"だから……","ENG":"So...","TWN":"所以……"},"stage":{"bg":"COUNTERSIDE_GARDEN","bgm":"HOUSE_OF_THE_RISING_SUN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"그런 슬픈 표정 짓지 마요, 엄마.","JPN":"そんな悲しい顔しないで、お母さん。","ENG":"Don't be so heartbroken, Mother.","TWN":"不要露出那樣悲傷的表情，媽媽。"},"stage":{"bg":"COUNTERSIDE_GARDEN","bgm":"HOUSE_OF_THE_RISING_SUN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"아.","JPN":"あっ。","ENG":"Ah.","TWN":"啊。"},"stage":{"bg":"COUNTERSIDE_GARDEN","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"생일날 먹기로 했던 토마토… 잊고 있었네.","JPN":"誕生日に食べるつもりだったトマト……忘れてた。","ENG":"The tomatoes I planned to eat on my birthday... I totally forgot about them.","TWN":"生日那天要吃蕃茄的……忘記摘了。"},"stage":{"bg":"COUNTERSIDE_GARDEN","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"지금쯤 빨갛게 잘 익었으려나?","JPN":"今頃真っ赤になってるかな？","ENG":"Would they be ripe and red by now?","TWN":"現在應該紅透了吧？"},"stage":{"bg":"COUNTERSIDE_GARDEN","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":null,"text":{"KOREA":"상처도, 침식도 한계로군.","JPN":"傷も、侵食も限界だな。","ENG":"The Corruption and your wounds have reached their limits.","TWN":"傷口和侵蝕都到極限了。"},"stage":{"bg":"SKY_RED","bgm":"THEMA_CS_ORCHESTRA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":null,"text":{"KOREA":"지금까지 잘 버텨줬다, 꼬마.","JPN":"今までよく耐えてくれた、ちび。","ENG":"You've held up well so far, kid.","TWN":"你能一直堅持到現在，真是個了不起的小鬼。"},"stage":{"bg":"SKY_RED","bgm":"THEMA_CS_ORCHESTRA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"SKY_RED","bgm":"THEMA_CS_ORCHESTRA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"당신은…?","JPN":"あなたは……？","ENG":"You are...?","TWN":"你是……？"},"stage":{"bg":"SKY_RED","bgm":"THEMA_CS_ORCHESTRA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"…영웅님?","JPN":"……英雄様？","ENG":"...the hero?","TWN":"……英雄?"},"stage":{"bg":"SKY_RED","bgm":"THEMA_CS_ORCHESTRA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NKM_NPC_PAST_HILDE_SILHOUETTE","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"NKM_NPC_PAST_HILDE_SILHOUETTE","text":{"KOREA":"난 영웅이 아니야.","JPN":"私は英雄ではない。","ENG":"I'm no hero.","TWN":"不，我不是她。"},"stage":{"bg":"SKY_RED","bgm":"THEMA_CS_ORCHESTRA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NKM_NPC_PAST_HILDE_SILHOUETTE","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"NKM_NPC_PAST_HILDE_SILHOUETTE","text":{"KOREA":"과거의 미련이 빚어낸 허상일 뿐이다.","JPN":"過去の未練が作り出した幻にすぎない。","ENG":"Just an illusion created by regrets of the past.","TWN":"只是由過去的執念所編織出的幻影而已。"},"stage":{"bg":"SKY_RED","bgm":"THEMA_CS_ORCHESTRA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NKM_NPC_PAST_HILDE_SILHOUETTE","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"HILDE_FENRIR_ADMIN_PAST","text":{"KOREA":"하지만…","JPN":"だが……","ENG":"However...","TWN":"不過……"},"stage":{"bg":"SKY_RED","bgm":"THEMA_CS_ORCHESTRA","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":"HILDE_FENRIR_ADMIN_PAST","text":{"KOREA":"네 운명을 가로막는 저 벽을 치우는 데엔 부족함이 없겠지.","JPN":"お前の運命を阻むあの壁を壊すくらいならできるだろう。","ENG":"I'll be enough to remove that wall blocking your fate.","TWN":"為你斬開擋在你命運面前的那堵牆還是綽綽有餘的。"},"stage":{"bg":"MS_1303","bgm":"THEMA_CS_ORCHESTRA","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"부러진 검이… 빛으로…?","JPN":"折れた剣が……光で……？","ENG":"The broken sword is... turning into light...?","TWN":"斷掉的劍……一閃一閃的……？"},"stage":{"bg":"MS_1303","bgm":"THEMA_CS_ORCHESTRA","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"싸우려는 건가요…? 위험해요…!","JPN":"戦うつもりですか……？　危険です……！","ENG":"Are you going to fight...? It's dangerous...!","TWN":"要戰鬥嗎……？很危險的……！"},"stage":{"bg":"MS_1303","bgm":"THEMA_CS_ORCHESTRA","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L13_1","type":"dialog","speaker":"HILDE_FENRIR_ADMIN_PAST","text":{"KOREA":"현실에서 날 만나게 되면 전해라.","JPN":"現実で私に会えたら、伝えてくれ。","ENG":"If you ever see me in the Normalside, deliver this message to me.","TWN":"如果在現實中遇到我，就告訴她吧。"},"stage":{"bg":"MS_1303","bgm":"THEMA_CS_ORCHESTRA","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L14_1","type":"dialog","speaker":"HILDE_FENRIR_ADMIN_PAST","text":{"KOREA":"네 어리석은 과거의 미련이… 옛 맹세를 지키려다 힘을 좀 쓰게 됐다고.","JPN":"愚かな過去の未練が……昔の誓いを守るために、力を少し消費したのだと。","ENG":"That the foolish regrets of your past... used some of your powers to keep an old vow.","TWN":"是的，她過去的那個愚蠢的執念……為了遵守昔日的誓言而偷偷用了點力量。"},"stage":{"bg":"MS_1303","bgm":"THEMA_CS_ORCHESTRA","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L17_1","type":"dialog","speaker":"HILDE_FENRIR_ADMIN_PAST","text":{"KOREA":"이런 결말로 만족하나?","JPN":"こんな結末で満足か？","ENG":"Are you satisfied with this ending?","TWN":"這樣的結局你滿意嗎？"},"stage":{"bg":"WHITE","bgm":"THEMA_CS_ORCHESTRA","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L18_1","type":"dialog","speaker":"MOM_NPC_BIRDCAGE_NULL","text":{"KOREA":"…스승님?","JPN":"……師匠？","ENG":"...Master?","TWN":"……師父?"},"stage":{"bg":"WHITE","bgm":"THEMA_CS_ORCHESTRA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MOM_NPC_BIRDCAGE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"HILDE_FENRIR_ADMIN_PAST","text":{"KOREA":"결국 내 힘을 사용하지 않았더군.","JPN":"結局、私の力は使わなかったんだな。","ENG":"I see you didn't use my powers in the end.","TWN":"你最終還是沒有使用我的力量啊。"},"stage":{"bg":"WHITE","bgm":"THEMA_CS_ORCHESTRA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_ADMIN_PAST","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"HILDE_FENRIR_ADMIN_PAST","text":{"KOREA":"넌 결정을 내리기 전에 이미 알고 있었다. 네 운명을 전부 바쳐도 그 아이가 어른이 될 때까지 버티지 못할 걸 말이야.","JPN":"わかっていたはずだ。お前の運命をすべて捧げても、あの子が大人になるまではもたないということを。","ENG":"You already knew before you even made your decision. That even sacrificing the entirety of your fate wouldn't be enough time for your child to become an adult.","TWN":"即使你在做決定之前就已經知道了，就算獻出自己全部的命運，也無法堅持到那個孩子長大成人。"},"stage":{"bg":"WHITE","bgm":"THEMA_CS_ORCHESTRA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_ADMIN_PAST","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"HILDE_FENRIR_ADMIN_PAST","text":{"KOREA":"아이가 성장하는 걸 지켜보는 게 네 소원이지 않았나? 그렇다면 왜 그런 결정을 한 거지?","JPN":"子どもが成長していく姿を見届けるのがお前の願いじゃなかったのか？　なのに、なぜあんな選択をした？","ENG":"Wasn't it your wish to watch your daughter grow? Then, why did you choose to do this?","TWN":"看著孩子成長不是你的願望嗎？為什麼要那樣做？"},"stage":{"bg":"WHITE","bgm":"THEMA_CS_ORCHESTRA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_ADMIN_PAST","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"MOM_NPC_BIRDCAGE_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"WHITE","bgm":"THEMA_CS_ORCHESTRA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MOM_NPC_BIRDCAGE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"MOM_NPC_BIRDCAGE_NULL","text":{"KOREA":"전 그저… 아이에게 희망을 가르쳐주고 싶었을 뿐이에요.","JPN":"私はただ……子どもに希望を教えてあげたかっただけです。","ENG":"I just... wanted to teach her hope.","TWN":"我只是……想教會她希望而已。"},"stage":{"bg":"WHITE","bgm":"THEMA_CS_ORCHESTRA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MOM_NPC_BIRDCAGE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"MOM_NPC_BIRDCAGE_NULL","text":{"KOREA":"자기 스승이 부탁한 미래도 저버린 어른이라면… 무슨 낯으로 그런 걸 가르치겠어요?","JPN":"自分の師匠に託された未来を裏切るような大人に……希望を教える資格はないでしょう？","ENG":"But how am I supposed to teach her that, if I'm someone who has abandoned the future my master asked to protect?","TWN":"但如果是連師父託付的未來都辜負了的大人……還有什麼臉去教別人呢……？"},"stage":{"bg":"WHITE","bgm":"THEMA_CS_ORCHESTRA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MOM_NPC_BIRDCAGE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"HILDE_FENRIR_ADMIN_PAST","text":{"KOREA":"참… 너다운 이유로군.","JPN":"まったく……お前らしい理由だ。","ENG":"That reason... is typical of you.","TWN":"真是……很符合你的風格。"},"stage":{"bg":"WHITE","bgm":"THEMA_CS_ORCHESTRA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_ADMIN_PAST","face":"UNIT_PRIDE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"MOM_NPC_BIRDCAGE_NULL","text":{"KOREA":"후후, 다 스승님의 가르침 덕분이죠.","JPN":"ふふ、師匠の教えのおかげです。","ENG":"Ha ha. It's all thanks to your teachings, Master.","TWN":"嘿嘿，這都是托師父的福啊。"},"stage":{"bg":"WHITE","bgm":"THEMA_CS_ORCHESTRA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MOM_NPC_BIRDCAGE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"MOM_NPC_BIRDCAGE_NULL","text":{"KOREA":"그러니…","JPN":"だから……","ENG":"So...","TWN":"所以……"},"stage":{"bg":"WHITE","bgm":"THEMA_CS_ORCHESTRA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_ADMIN_PAST","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"MOM_NPC_BIRDCAGE_NULL","text":{"KOREA":"미래를 부탁 드려요.","JPN":"未来をよろしくお願いします。","ENG":"I leave the future in your hands.","TWN":"未來就拜託你了。"},"stage":{"bg":"WHITE","bgm":"THEMA_CS_ORCHESTRA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_ADMIN_PAST","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"HILDE_FENRIR_ADMIN_PAST","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"WHITE","bgm":"THEMA_CS_ORCHESTRA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_ADMIN_PAST","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"HILDE_FENRIR_ADMIN_PAST","text":{"KOREA":"알겠다.","JPN":"わかった。","ENG":"Okay.","TWN":"知道了。"},"stage":{"bg":"WHITE","bgm":"THEMA_CS_ORCHESTRA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_ADMIN_PAST","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"HILDE_FENRIR_ADMIN_PAST","text":{"KOREA":"뒤는 걱정 말고 편히 쉬어라.","JPN":"あとのことは心配するな、もうゆっくり休んでいい。","ENG":"Leave the rest to me, and rest in peace.","TWN":"剩下的我來，安息吧。"},"stage":{"bg":"WHITE","bgm":"THEMA_CS_ORCHESTRA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_ADMIN_PAST","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};